46	function buildOutputField(field: DMMF.SchemaField) {
47	  let fieldType: ts.TypeBuilder
48	
49	  if (field.outputType.location === 'enumTypes' && field.outputType.namespace === 'model') {
50	    fieldType = ts.namedType(enumTypeName(field.outputType))
51	  } else {
52	    const typeNames = GraphQLScalarToJSTypeTable[field.outputType.type] ?? field.outputType.type
53	    fieldType = Array.isArray(typeNames) ? ts.namedType(typeNames[0]) : ts.namedType(typeNames)
54	  }
55	
56	  if (field.outputType.isList) {
57	    fieldType = ts.array(fieldType)
58	  } else if (field.isNullable) {
59	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
60	  }
61	
62	  const property = ts.property(field.name, fieldType)
63	  if (field.deprecation) {
64	    property.setDocComment(
