generatorHandler({
  async onGenerate(options: GeneratorOptions) {
    const dmmf = options.dmmf

    // Iterate models
    for (const model of dmmf.datamodel.models) {
      console.log(`Model: ${model.name}`)

      // Iterate fields
      for (const field of model.fields) {
        if (field.kind === 'scalar') {
          console.log(`  Scalar: ${field.name}: ${field.type}`)
        } else if (field.kind === 'object') {
          console.log(`  Relation: ${field.name} -> ${field.type}`)
          console.log(`    Foreign keys: ${field.relationFromFields}`)
        } else if (field.kind === 'enum') {
          console.log(`  Enum: ${field.name}: $${field.type}`)
        }

        // Check field characteristics
        if (field.isId) console.log(`    (primary key)`)
        if (field.isUnique) console.log(`    (unique)`)
        if (!field.isRequired) console.log(`    (optional)`)
        if (field.isList) console.log(`    (array)`)
      }
    }

    // Access enums
    for (const enum_ of dmmf.datamodel.enums) {
      console.log(`Enum ${enum_.name}: ${enum_.values.map(v => v.name).join(', ')}`)
    }

    // Access model operation mappings
    for (const mapping of dmmf.mappings.modelOperations) {
      console.log(`Model ${mapping.model}: ${mapping.plural}`)
      console.log(`  Operations: ${Object.entries(mapping).filter(([k, v]) => v).map(([k]) => k).join(', ')}`)
    }
  }
})
