import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

import { mapScalarType } from './scalar-type-map'

/** Converts PascalCase to camelCase: `"UserProfile"` → `"userProfile"` */
export function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/** Simple English pluralization for REST endpoint paths. */
export function toPlural(name: string): string {
  const lower = name.toLowerCase()
  if (lower.endsWith('s') || lower.endsWith('x') || lower.endsWith('z') || lower.endsWith('sh') || lower.endsWith('ch')) {
    return lower + 'es'
  }
  if (lower.endsWith('y') && !['a', 'e', 'i', 'o', 'u'].includes(lower.charAt(lower.length - 2))) {
    return lower.slice(0, -1) + 'ies'
  }
  return lower + 's'
}

/** Resolves a DMMF field to its TypeScript type string. */
export function fieldToTsType(field: Field, enums: readonly DatamodelEnum[]): string {
  let baseType: string

  if (field.kind === 'enum') {
    const enumExists = enums.some((e) => e.name === field.type)
    baseType = enumExists ? field.type : 'string'
  } else {
    baseType = mapScalarType(field.type)
  }

  if (field.isList) {
    baseType = `${baseType}[]`
  }

  if (!field.isRequired && !field.isList) {
    baseType = `${baseType} | null`
  }

  return baseType
}

/**
 * Returns true for fields that should be excluded from create inputs:
 * auto-increment IDs, `@updatedAt` fields, and generated fields.
 */
export function isAutoGeneratedField(field: Field): boolean {
  if (field.isUpdatedAt) {
    return true
  }
  if (field.isGenerated) {
    return true
  }
  if (field.isId && field.hasDefaultValue) {
    return true
  }
  return false
}

/**
 * Returns the fields that uniquely identify a record.
 * Checks single `@id`, composite `@@id`, then falls back to the first `@@unique`.
 */
export function getIdentityFields(model: Model): Field[] {
  const idFields = model.fields.filter((f) => f.isId)
  if (idFields.length > 0) {
    return [...idFields]
  }

  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const fieldMap = new Map(model.fields.map((f) => [f.name, f]))
    return model.primaryKey.fields.map((name) => fieldMap.get(name)).filter((f): f is Field => f !== undefined)
  }

  if (model.uniqueIndexes.length > 0) {
    const firstUnique = model.uniqueIndexes[0]
    const fieldMap = new Map(model.fields.map((f) => [f.name, f]))
    return firstUnique.fields.map((name) => fieldMap.get(name)).filter((f): f is Field => f !== undefined)
  }

  return []
}

/** Returns only the scalar and enum fields from a model (no relations). */
export function getScalarFields(model: Model): Field[] {
