import type { DatamodelEnum, Model } from '@prisma/dmmf'

import { fieldToTsType, getIdentityFields, getScalarFields, isAutoGeneratedField } from './utils'

/** Generates all TypeScript interfaces for a single model. */
export function generateModelTypes(model: Model, enums: readonly DatamodelEnum[]): string {
  const sections: string[] = [
    generateBaseInterface(model, enums),
    generateCreateInput(model, enums),
    generateUpdateInput(model, enums),
    generateWhereUniqueInput(model, enums),
  ]

  return sections.join('\n\n')
}

function generateBaseInterface(model: Model, enums: readonly DatamodelEnum[]): string {
  const fields = getScalarFields(model)
  const lines = fields.map((field) => {
    const tsType = fieldToTsType(field, enums)
    return `  ${field.name}: ${tsType}`
  })

  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

function generateCreateInput(model: Model, enums: readonly DatamodelEnum[]): string {
  const fields = getScalarFields(model).filter((f) => !isAutoGeneratedField(f))
  const identityFieldNames = new Set(getIdentityFields(model).map((f) => f.name))

  const lines = fields.map((field) => {
    const tsType = fieldToTsType(field, enums)
    const isOptional = field.hasDefaultValue || (!field.isRequired && !identityFieldNames.has(field.name))
    const optionalMark = isOptional ? '?' : ''
    return `  ${field.name}${optionalMark}: ${tsType}`
  })

  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

function generateUpdateInput(model: Model, enums: readonly DatamodelEnum[]): string {
  const identityFieldNames = new Set(getIdentityFields(model).map((f) => f.name))
  const fields = getScalarFields(model).filter((f) => !identityFieldNames.has(f.name) && !f.isUpdatedAt)

  const lines = fields.map((field) => {
    const tsType = fieldToTsType(field, enums)
    return `  ${field.name}?: ${tsType}`
  })

  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

function generateWhereUniqueInput(model: Model, enums: readonly DatamodelEnum[]): string {
  const identityFields = getIdentityFields(model)

  if (identityFields.length === 0) {
    return `// No unique identifier found for model ${model.name}\nexport type ${model.name}WhereUniqueInput = Record<string, never>`
  }

  const lines = identityFields.map((field) => {
    const tsType = fieldToTsType(field, enums)
    return `  ${field.name}: ${tsType}`
  })

  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

