import type { Model } from '@prisma/dmmf'

import { getIdentityFields, toCamelCase, toPlural } from './utils'

/** Generates the CRUD method object literal for a model accessor in the client class. */
export function generateCrudMethods(model: Model): string {
  const modelName = model.name
  const endpoint = toPlural(modelName)
  const accessor = toCamelCase(modelName)
  const identityFields = getIdentityFields(model)
  const hasIdentity = identityFields.length > 0

  const whereParam = hasIdentity ? buildWhereToPath(identityFields, endpoint) : null

  const methods: string[] = []

  // findMany
  methods.push(
    `      findMany: (params?: FindManyParams): Promise<${modelName}[]> => {
        const queryParams: Record<string, string> = {}
        if (params?.skip !== undefined) queryParams['skip'] = String(params.skip)
        if (params?.take !== undefined) queryParams['take'] = String(params.take)
        return request<${modelName}[]>(this.baseUrl, this.fetchFn, 'GET', '/${endpoint}', undefined, queryParams)
      }`,
  )

  if (hasIdentity) {
    // findUnique
    methods.push(
      `      findUnique: (where: ${modelName}WhereUniqueInput): Promise<${modelName} | null> =>
        request<${modelName} | null>(this.baseUrl, this.fetchFn, 'GET', ${whereParam})`,
    )

    // create
    methods.push(
      `      create: (data: ${modelName}CreateInput): Promise<${modelName}> =>
        request<${modelName}>(this.baseUrl, this.fetchFn, 'POST', '/${endpoint}', data)`,
    )

    // update
    methods.push(
      `      update: (where: ${modelName}WhereUniqueInput, data: ${modelName}UpdateInput): Promise<${modelName}> =>
        request<${modelName}>(this.baseUrl, this.fetchFn, 'PUT', ${whereParam}, data)`,
    )

    // delete
    methods.push(
      `      delete: (where: ${modelName}WhereUniqueInput): Promise<${modelName}> =>
        request<${modelName}>(this.baseUrl, this.fetchFn, 'DELETE', ${whereParam})`,
    )
  }

  return `    get ${accessor}() {
    return {
${methods.join(',\n')}
    }
  }`
}

/** Builds the URL expression for identity-based lookups. */
function buildWhereToPath(identityFields: readonly { name: string }[], endpoint: string): string {
  if (identityFields.length === 1) {
    return `\`/${endpoint}/\${where.${identityFields[0].name}}\``
  }
  // Composite key: encode as query-string
  const parts = identityFields.map((f) => `${f.name}=\${encodeURIComponent(String(where.${f.name}))}`)
  return `\`/${endpoint}?${parts.join('&')}\``
}

