import type { DatamodelEnum, Model } from '@prisma/dmmf'

import { generateCrudMethods } from './generate-crud-methods'
import { generateEnums } from './generate-enums'
import { generateModelTypes } from './generate-model-types'

/** Generates the full REST API client source file contents. */
export function generateClientFile(
  models: readonly Model[],
  enums: readonly DatamodelEnum[],
  baseUrl: string,
): string {
  const sections: string[] = []

  // Header
  sections.push(`// ===========================================================
// Generated by @prisma/generator-rest-api
// Do not edit manually.
// ===========================================================`)

  // Enums
  const enumCode = generateEnums(enums)
  if (enumCode) {
    sections.push(enumCode)
  }

  // Model types
  for (const model of models) {
    if (model.isGenerated) continue
    sections.push(generateModelTypes(model, enums))
  }

  // Shared types and request helper
  sections.push(generateRequestHelper(baseUrl))

  // Client class
  sections.push(generateRestApiClientClass(models))

  return sections.join('\n\n') + '\n'
}

function generateRequestHelper(baseUrl: string): string {
  return `type FetchFn = (input: string | URL | Request, init?: RequestInit) => Promise<Response>

type FindManyParams = {
  skip?: number
  take?: number
}

async function request<T>(
  baseUrl: string,
  fetchFn: FetchFn,
  method: string,
  path: string,
  body?: unknown,
  params?: Record<string, string>,
): Promise<T> {
  let url = baseUrl + path
  if (params) {
    const searchParams = new URLSearchParams()
    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined && value !== '') {
        searchParams.set(key, value)
      }
    }
    const qs = searchParams.toString()
    if (qs) {
      url += (url.includes('?') ? '&' : '?') + qs
    }
  }
  const response = await fetchFn(url, {
    method,
    headers: body !== undefined ? { 'Content-Type': 'application/json' } : undefined,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })
  if (!response.ok) {
    throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
  }
  return response.json() as Promise<T>
}`
}

function generateRestApiClientClass(models: readonly Model[]): string {
  const accessors = models.filter((m) => !m.isGenerated).map((model) => generateCrudMethods(model))

  return `export class RestApiClient {
  readonly #baseUrl: string
  readonly #fetchFn: FetchFn

  constructor(baseUrl: string, fetchFn: FetchFn = fetch) {
    this.#baseUrl = baseUrl
    this.#fetchFn = fetchFn
  }

  private get baseUrl(): string {
    return this.#baseUrl
  }

  private get fetchFn(): FetchFn {
    return this.#fetchFn
  }

${accessors.join('\n\n')}
}`
}

