  test('returns single @id field', () => {
    const idField = makeField({ name: 'id', isId: true, type: 'Int' })
    const model = makeModel({ fields: [idField, makeField({ name: 'name' })] })
    expect(getIdentityFields(model).map((f) => f.name)).toEqual(['id'])
  })

  test('returns composite @@id fields', () => {
    const fieldA = makeField({ name: 'tenantId', type: 'String' })
    const fieldB = makeField({ name: 'userId', type: 'String' })
    const model = makeModel({
      fields: [fieldA, fieldB],
      primaryKey: { name: null, fields: ['tenantId', 'userId'] },
    })
    expect(getIdentityFields(model).map((f) => f.name)).toEqual(['tenantId', 'userId'])
  })

  test('falls back to first @@unique', () => {
    const fieldA = makeField({ name: 'email', type: 'String' })
    const fieldB = makeField({ name: 'orgId', type: 'String' })
    const model = makeModel({
      fields: [fieldA, fieldB],
      uniqueIndexes: [{ name: 'email_orgId', fields: ['email', 'orgId'] }],
    })
    expect(getIdentityFields(model).map((f) => f.name)).toEqual(['email', 'orgId'])
  })

  test('returns empty array when no identity', () => {
    const model = makeModel({ fields: [makeField({ name: 'data' })] })
    expect(getIdentityFields(model)).toEqual([])
  })
})

