import type { Field, Model } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateModelTypes } from '../codegen/generate-model-types'

function makeField(overrides: Partial<Field> = {}): Field {
  return {
    kind: 'scalar',
    name: 'testField',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

function makeModel(overrides: Partial<Model> = {}): Model {
  return {
    name: 'TestModel',
    dbName: null,
    schema: null,
    fields: [],
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as Model
}

describe('generateModelTypes', () => {
  test('generates interfaces for a simple model', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String', isRequired: false }),
      ],
    })

    const result = generateModelTypes(model, [])

    // Base interface
    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name: string | null')

    // CreateInput - id excluded (autoincrement), name optional (nullable)
    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name?: string | null')
    expect(result).not.toMatch(/UserCreateInput[\s\S]*?\bid: number/)

    // UpdateInput - id excluded (identity), name optional
    expect(result).toContain('export interface UserUpdateInput {')
    expect(result).toMatch(/UserUpdateInput[\s\S]*?email\?: string/)
    expect(result).toMatch(/UserUpdateInput[\s\S]*?name\?: string \| null/)

    // WhereUniqueInput
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toMatch(/UserWhereUniqueInput[\s\S]*?id: number/)
  })

  test('excludes relation fields from interfaces', () => {
    const model = makeModel({
      name: 'Post',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'authorId', type: 'Int', isReadOnly: true }),
        makeField({ kind: 'object', name: 'author', type: 'User', isRequired: true }),
      ],
    })

    const result = generateModelTypes(model, [])

    expect(result).toContain('  authorId: number')
    expect(result).not.toContain('  author:')
  })

  test('makes fields with default values optional in CreateInput', () => {
    const model = makeModel({
      name: 'Article',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'published', type: 'Boolean', hasDefaultValue: true }),
      ],
    })

    const result = generateModelTypes(model, [])

    // published should be optional in CreateInput because it has a default
    expect(result).toMatch(/ArticleCreateInput[\s\S]*?published\?: boolean/)
    // published should be required in base interface
    expect(result).toMatch(/export interface Article \{[\s\S]*?published: boolean/)
  })

  test('excludes @updatedAt fields from CreateInput and UpdateInput', () => {
    const model = makeModel({
      name: 'Record',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'data', type: 'String' }),
        makeField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
      ],
    })

    const result = generateModelTypes(model, [])

    // updatedAt in base interface
    expect(result).toMatch(/export interface Record \{[\s\S]*?updatedAt: string/)
    // not in CreateInput
    expect(result).not.toMatch(/RecordCreateInput[\s\S]*?updatedAt/)
    // not in UpdateInput
    expect(result).not.toMatch(/RecordUpdateInput[\s\S]*?updatedAt/)
  })

  test('handles enum fields', () => {
    const enums = [
      {
        name: 'Role',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
        ],
      },
    ]

    const model = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ kind: 'enum', name: 'role', type: 'Role' }),
      ],
    })

    const result = generateModelTypes(model, enums)

    expect(result).toContain('  role: Role')
  })

  test('handles list fields', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'tags', type: 'String', isList: true }),
      ],
    })

    const result = generateModelTypes(model, [])

    expect(result).toContain('  tags: string[]')
  })

  test('handles composite @@id', () => {
    const model = makeModel({
      name: 'Membership',
      fields: [
        makeField({ name: 'userId', type: 'Int' }),
        makeField({ name: 'orgId', type: 'Int' }),
        makeField({ name: 'role', type: 'String' }),
      ],
      primaryKey: { name: null, fields: ['userId', 'orgId'] },
    })

    const result = generateModelTypes(model, [])

    expect(result).toContain('export interface MembershipWhereUniqueInput {')
    expect(result).toMatch(/MembershipWhereUniqueInput[\s\S]*?userId: number/)
    expect(result).toMatch(/MembershipWhereUniqueInput[\s\S]*?orgId: number/)
  })
})

