    uniqueIndexes: [],
    primaryKey: null,
    ...overrides,
  } as Model
}

describe('generateClientFile', () => {
  test('generates a complete client file with header', () => {
    const models = [
      makeModel({
        name: 'User',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'email', type: 'String' }),
        ],
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    expect(result).toContain('Generated by @prisma/generator-rest-api')
    expect(result).toContain('Do not edit manually.')
  })

  test('generates model accessors in the client class', () => {
    const models = [
      makeModel({
        name: 'User',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'email', type: 'String' }),
        ],
      }),
      makeModel({
        name: 'Post',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'title', type: 'String' }),
        ],
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    expect(result).toContain('export class RestApiClient')
    expect(result).toContain('get user()')
    expect(result).toContain('get post()')
  })

  test('generates all CRUD methods', () => {
    const models = [
      makeModel({
        name: 'User',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'name', type: 'String' }),
        ],
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    expect(result).toContain('findMany:')
    expect(result).toContain('findUnique:')
    expect(result).toContain('create:')
    expect(result).toContain('update:')
    expect(result).toContain('delete:')
  })

  test('generates correct REST endpoints', () => {
    const models = [
      makeModel({
        name: 'User',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ name: 'email', type: 'String' }),
        ],
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    expect(result).toContain("'/users'")
    expect(result).toContain('`/users/${where.id}`')
  })

  test('includes enums when present', () => {
    const enums = [
      {
        name: 'Role',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
        ],
      },
    ]

    const models = [
      makeModel({
        name: 'User',
        fields: [
          makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          makeField({ kind: 'enum', name: 'role', type: 'Role' }),
        ],
      }),
    ]

    const result = generateClientFile(models, enums, '/api')

    expect(result).toContain('export enum Role')
    expect(result).toContain("ADMIN = 'ADMIN'")
  })

  test('generates the request helper function', () => {
    const result = generateClientFile(
      [
        makeModel({
          name: 'User',
          fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
        }),
      ],
      [],
      '/api',
    )

    expect(result).toContain('async function request<T>')
    expect(result).toContain('type FetchFn')
    expect(result).toContain('type FindManyParams')
  })

  test('skips generated models', () => {
    const models = [
      makeModel({
        name: 'User',
        isGenerated: true,
        fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      }),
      makeModel({
        name: 'Post',
        fields: [makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true })],
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    expect(result).not.toContain('get user()')
    expect(result).toContain('get post()')
  })

  test('handles composite key URLs', () => {
    const models = [
      makeModel({
        name: 'Membership',
        fields: [
          makeField({ name: 'userId', type: 'Int' }),
          makeField({ name: 'orgId', type: 'Int' }),
          makeField({ name: 'role', type: 'String' }),
        ],
        primaryKey: { name: null, fields: ['userId', 'orgId'] },
      }),
    ]

    const result = generateClientFile(models, [], '/api')

    // Composite keys use query-string encoding
    expect(result).toContain('userId=')
    expect(result).toContain('orgId=')
  })
})

